<?php
 namespace League\CommonMark\Block\Parser; use League\CommonMark\Block\Element\IndentedCode; use League\CommonMark\Block\Element\Paragraph; use League\CommonMark\ContextInterface; use League\CommonMark\Cursor; final class IndentedCodeParser implements BlockParserInterface { public function parse(ContextInterface $context, Cursor $cursor): bool { if (!$cursor->isIndented()) { return false; } if ($context->getTip() instanceof Paragraph) { return false; } if ($cursor->isBlank()) { return false; } $cursor->advanceBy(Cursor::INDENT_LEVEL, true); $context->addBlock(new IndentedCode()); return true; } } 